// Başlanğıc rəqəm
let ingredientCount = 3.14159; // Pi, məsələn, yumurta sayı :)

// 1. toString: Rəqəmi stringə çevirir
console.log(ingredientCount.toString()); // nəticə: "3.14159"
console.log(ingredientCount.toString(2)); // nəticə: "11.001001000011111" (ikilik sistem)

// 2. toFixed: Ondalık hissəni sabit sayda rəqəmlə göstərir
console.log(ingredientCount.toFixed(2)); // nəticə: "3.14"
console.log(ingredientCount.toFixed(0)); // nəticə: "3"

// 3. toPrecision: Rəqəmi müəyyən dəqiqliklə göstərir
console.log(ingredientCount.toPrecision(3)); // nəticə: "3.14"
console.log(ingredientCount.toPrecision(5)); // nəticə: "3.1416"

// 4. toExponential: Rəqəmi eksponensial formada göstərir
console.log(ingredientCount.toExponential(2)); // nəticə: "3.14e+0"
console.log((1234.567).toExponential(1)); // nəticə: "1.2e+3"

// 5. valueOf: Rəqəmin primitiv dəyərini qaytarır
console.log(ingredientCount.valueOf()); // nəticə: 3.14159

// 6. Number.isFinite: Rəqəmin sonlu olub-olmadığını yoxlayır
console.log(Number.isFinite(ingredientCount)); // nəticə: true
console.log(Number.isFinite(Infinity)); // nəticə: false

// 7. Number.isInteger: Rəqəmin tam say olub-olmadığını yoxlayır
console.log(Number.isInteger(5)); // nəticə: true
console.log(Number.isInteger(ingredientCount)); // nəticə: false

// 8. Number.isNaN: Rəqəmin NaN (Not-a-Number) olub-olmadığını yoxlayır
console.log(Number.isNaN(ingredientCount)); // nəticə: false
console.log(Number.isNaN(NaN)); // nəticə: true

// 9. Number.isSafeInteger: Rəqəmin təhlükəsiz tam say olub-olmadığını yoxlayır
console.log(Number.isSafeInteger(9007199254740991)); // nəticə: true
console.log(Number.isSafeInteger(9007199254740992)); // nəticə: false

// 10. Number.parseFloat: Stringdən ondalık rəqəm çıxarır
console.log(Number.parseFloat("3.14 yumurta")); // nəticə: 3.14
console.log(Number.parseFloat("10.5")); // nəticə: 10.5

// 11. Number.parseInt: Stringdən tam say çıxarır
console.log(Number.parseInt("10 yumurta")); // nəticə: 10
console.log(Number.parseInt("10.5", 10)); // nəticə: 10

// Yuvarlaqlaşdırma səhvi
let num = 0.1 + 0.2;
console.log(num.toFixed(2)); // nəticə: "0.30" (dəqiq nəticə gözlənilir)

// NaN ilə işləmə
let invalid = Number.parseFloat("yoxdur");
console.log(Number.isNaN(invalid)); // nəticə: true

// Böyük rəqəmlər
let bigNum = 9007199254740992;
console.log(Number.isSafeInteger(bigNum)); // nəticə: false

