// Starting number
let ingredientCount = 3.14159; // Pi, like the number of eggs :)

// 1. toString: Converts a number to a string
console.log(ingredientCount.toString()); // Output: "3.14159"
console.log(ingredientCount.toString(2)); // Output: "11.001001000011111" (binary)

// 2. toFixed: Formats with a fixed number of decimal places
console.log(ingredientCount.toFixed(2)); // Output: "3.14"
console.log(ingredientCount.toFixed(0)); // Output: "3"

// 3. toPrecision: Formats with a specified precision
console.log(ingredientCount.toPrecision(3)); // Output: "3.14"
console.log(ingredientCount.toPrecision(5)); // Output: "3.1416"

// 4. toExponential: Formats in exponential notation
console.log(ingredientCount.toExponential(2)); // Output: "3.14e+0"
console.log((1234.567).toExponential(1)); // Output: "1.2e+3"

// 5. valueOf: Returns the primitive value of a number
console.log(ingredientCount.valueOf()); // Output: 3.14159

// 6. Number.isFinite: Checks if a number is finite
console.log(Number.isFinite(ingredientCount)); // Output: true
console.log(Number.isFinite(Infinity)); // Output: false

// 7. Number.isInteger: Checks if a number is an integer
console.log(Number.isInteger(5)); // Output: true
console.log(Number.isInteger(ingredientCount)); // Output: false

// 8. Number.isNaN: Checks if a value is NaN (Not-a-Number)
console.log(Number.isNaN(ingredientCount)); // Output: false
console.log(Number.isNaN(NaN)); // Output: true

// 9. Number.isSafeInteger: Checks if a number is a safe integer
console.log(Number.isSafeInteger(9007199254740991)); // Output: true
console.log(Number.isSafeInteger(9007199254740992)); // Output: false

// 10. Number.parseFloat: Parses a string to a floating-point number
console.log(Number.parseFloat("3.14 eggs")); // Output: 3.14
console.log(Number.parseFloat("10.5")); // Output: 10.5

// 11. Number.parseInt: Parses a string to an integer
console.log(Number.parseInt("10 eggs")); // Output: 10
console.log(Number.parseInt("10.5", 10)); // Output: 10

// Rounding error
let num = 0.1 + 0.2;
console.log(num.toFixed(2)); // Output: "0.30" (expected result)

// Handling NaN
let invalid = Number.parseFloat("none");
console.log(Number.isNaN(invalid)); // Output: true

// Large numbers
let bigNum = 9007199254740992;
console.log(Number.isSafeInteger(bigNum)); // Output: false

