// Начальное число
let ingredientCount = 3.14159; // Пи, например, количество яиц :)

// 1. toString: Преобразует число в строку
console.log(ingredientCount.toString()); // Вывод: "3.14159"
console.log(ingredientCount.toString(2)); // Вывод: "11.001001000011111" (двоичная система)

// 2. toFixed: Форматирует с фиксированным количеством десятичных знаков
console.log(ingredientCount.toFixed(2)); // Вывод: "3.14"
console.log(ingredientCount.toFixed(0)); // Вывод: "3"

// 3. toPrecision: Форматирует с заданной точностью
console.log(ingredientCount.toPrecision(3)); // Вывод: "3.14"
console.log(ingredientCount.toPrecision(5)); // Вывод: "3.1416"

// 4. toExponential: Форматирует в экспоненциальной нотации
console.log(ingredientCount.toExponential(2)); // Вывод: "3.14e+0"
console.log((1234.567).toExponential(1)); // Вывод: "1.2e+3"

// 5. valueOf: Возвращает примитивное значение числа
console.log(ingredientCount.valueOf()); // Вывод: 3.14159

// 6. Number.isFinite: Проверяет, является ли число конечным
console.log(Number.isFinite(ingredientCount)); // Вывод: true
console.log(Number.isFinite(Infinity)); // Вывод: false

// 7. Number.isInteger: Проверяет, является ли число целым
console.log(Number.isInteger(5)); // Вывод: true
console.log(Number.isInteger(ingredientCount)); // Вывод: false

// 8. Number.isNaN: Проверяет, является ли значение NaN (Not-a-Number)
console.log(Number.isNaN(ingredientCount)); // Вывод: false
console.log(Number.isNaN(NaN)); // Вывод: true

// 9. Number.isSafeInteger: Проверяет, является ли число безопасным целым
console.log(Number.isSafeInteger(9007199254740991)); // Вывод: true
console.log(Number.isSafeInteger(9007199254740992)); // Вывод: false

// 10. Number.parseFloat: Извлекает число с плавающей точкой из строки
console.log(Number.parseFloat("3.14 яиц")); // Вывод: 3.14
console.log(Number.parseFloat("10.5")); // Вывод: 10.5

// 11. Number.parseInt: Извлекает целое число из строки
console.log(Number.parseInt("10 яиц")); // Вывод: 10
console.log(Number.parseInt("10.5", 10)); // Вывод: 10

// Ошибка округления
let num = 0.1 + 0.2;
console.log(num.toFixed(2)); // Вывод: "0.30" (ожидаемый результат)

// Работа с NaN
let invalid = Number.parseFloat("нет");
console.log(Number.isNaN(invalid)); // Вывод: true

// Большие числа
let bigNum = 9007199254740992;
console.log(Number.isSafeInteger(bigNum)); // Вывод: false

